#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10;int n,k,Q,a[N*5],idx[N],mn[N<<2],nxt[N*5],lst[N];
inline void update(const int &x)
{
	if(!mn[x<<1]||!mn[x<<1|1])mn[x]=mn[x<<1]|mn[x<<1|1];
	else{mn[x]=nxt[mn[x<<1]]>nxt[mn[x<<1|1]]?mn[x<<1]:mn[x<<1|1];}
}
inline void build(const int &l=1,const int &r=n,const int &cur=1)
{
	if(l==r)return idx[l]=cur,void();const int &mid=(l+r)>>1;
	build(l,mid,cur<<1);build(mid+1,r,cur<<1|1);
}
inline void add(int p,int w){int x=idx[p];mn[x]=w;while(x!=1)update(x=x>>1);}
inline bool vis(int p){return mn[idx[p]];}
inline void Solve()
{
	memset(nxt,0,sizeof(nxt));
	memset(lst,0,sizeof(lst));
	memset(mn,0,sizeof(mn));
	n=read();k=read();Q=read();int ans=0;
	rep(1,Q,i)nxt[lst[a[i]=read()]]=i,lst[a[i]]=i;
	rep(1,n,i)nxt[lst[i]]=Q+1;build();int K=0;
	rep(1,Q,i)
	{
		if(vis(a[i])){add(a[i],i);continue;}
		if(K<k){add(a[i],i);++K;++ans;continue;}
		add(a[mn[1]],0);add(a[i],i);++ans;
	}
	printf("%d\n",ans);return;
}
int main(){int T=read();while(T--)Solve();return 0;}
